import uuid
import pytest
from datetime import date, timedelta

def test_create_savings_goal_different_idempotency_keys_create_separate_goals(auth_headers, api_base_url, http_client):
    target_date = (date.today() + timedelta(days=200)).isoformat()
    payload = {"target_amount": 250.00, "target_date": target_date}

    headers_a = {**auth_headers, "Idempotency-Key": str(uuid.uuid4())}
    headers_b = {**auth_headers, "Idempotency-Key": str(uuid.uuid4())}

    resp_a = http_client.post(f"{api_base_url}/goals", json=payload, headers=headers_a)
    resp_b = http_client.post(f"{api_base_url}/goals", json=payload, headers=headers_b)

    assert resp_a.status_code == 201
    assert resp_b.status_code == 201
    assert resp_a.json()["goal_id"] != resp_b.json()["goal_id"]
